class $$WarehousesTableTableManager
    extends
        RootTableManager<
          _$AppDatabase,
          $WarehousesTable,
          WarehouseData,
          $$WarehousesTableFilterComposer,
          $$WarehousesTableOrderingComposer,
          $$WarehousesTableAnnotationComposer,
          $$WarehousesTableCreateCompanionBuilder,
          $$WarehousesTableUpdateCompanionBuilder,
          (WarehouseData, $$WarehousesTableReferences),
          WarehouseData,
          PrefetchHooks Function({
            bool businessId,
            bool usersRefs,
            bool customersRefs,
            bool ordersRefs,
            bool inventoryRefs,
            bool stockAdjustmentsRefs,
            bool stockTransactionsRefs,
            bool orderItemsRefs,
            bool expensesRefs,
            bool activityLogsRefs,
            bool invitesRefs,
          })
        > {
  $$WarehousesTableTableManager(_$AppDatabase db, $WarehousesTable table)
    : super(
        TableManagerState(
          db: db,
          table: table,
          createFilteringComposer: () =>
              $$WarehousesTableFilterComposer($db: db, $table: table),
          createOrderingComposer: () =>
              $$WarehousesTableOrderingComposer($db: db, $table: table),
          createComputedFieldComposer: () =>
              $$WarehousesTableAnnotationComposer($db: db, $table: table),
          updateCompanionCallback:
              ({
                Value<String> id = const Value.absent(),
                Value<String> businessId = const Value.absent(),
                Value<String> name = const Value.absent(),
                Value<String?> location = const Value.absent(),
                Value<bool> isDeleted = const Value.absent(),
                Value<DateTime> createdAt = const Value.absent(),
                Value<DateTime> lastUpdatedAt = const Value.absent(),
                Value<int> rowid = const Value.absent(),
              }) => WarehousesCompanion(
                id: id,
                businessId: businessId,
                name: name,
                location: location,
                isDeleted: isDeleted,
                createdAt: createdAt,
                lastUpdatedAt: lastUpdatedAt,
                rowid: rowid,
              ),
          createCompanionCallback:
              ({
                Value<String> id = const Value.absent(),
                required String businessId,
                required String name,
                Value<String?> location = const Value.absent(),
                Value<bool> isDeleted = const Value.absent(),
                Value<DateTime> createdAt = const Value.absent(),
                Value<DateTime> lastUpdatedAt = const Value.absent(),
                Value<int> rowid = const Value.absent(),
              }) => WarehousesCompanion.insert(
                id: id,
                businessId: businessId,
                name: name,
                location: location,
                isDeleted: isDeleted,
                createdAt: createdAt,
                lastUpdatedAt: lastUpdatedAt,
                rowid: rowid,
              ),
          withReferenceMapper: (p0) => p0
              .map(
                (e) => (
                  e.readTable(table),
                  $$WarehousesTableReferences(db, table, e),
                ),
              )
              .toList(),
          prefetchHooksCallback:
              ({
                businessId = false,
                usersRefs = false,
                customersRefs = false,
                ordersRefs = false,
                inventoryRefs = false,
                stockAdjustmentsRefs = false,
                stockTransactionsRefs = false,
                orderItemsRefs = false,
                expensesRefs = false,
                activityLogsRefs = false,
                invitesRefs = false,
              }) {
                return PrefetchHooks(
                  db: db,
                  explicitlyWatchedTables: [
                    if (usersRefs) db.users,
                    if (customersRefs) db.customers,
                    if (ordersRefs) db.orders,
                    if (inventoryRefs) db.inventory,
                    if (stockAdjustmentsRefs) db.stockAdjustments,
                    if (stockTransactionsRefs) db.stockTransactions,
                    if (orderItemsRefs) db.orderItems,
                    if (expensesRefs) db.expenses,
                    if (activityLogsRefs) db.activityLogs,
                    if (invitesRefs) db.invites,
                  ],
                  addJoins:
                      <
                        T extends TableManagerState<
                          dynamic,
                          dynamic,
                          dynamic,
                          dynamic,
                          dynamic,
                          dynamic,
                          dynamic,
                          dynamic,
                          dynamic,
                          dynamic,
                          dynamic
                        >
                      >(state) {
                        if (businessId) {
                          state =
                              state.withJoin(
                                    currentTable: table,
                                    currentColumn: table.businessId,
                                    referencedTable: $$WarehousesTableReferences
                                        ._businessIdTable(db),
                                    referencedColumn:
                                        $$WarehousesTableReferences
                                            ._businessIdTable(db)
                                            .id,
                                  )
                                  as T;
                        }

                        return state;
                      },
                  getPrefetchedDataCallback: (items) async {
                    return [
